1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const basePremiumOf = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
19	
20	const quoteForStep = (step: QuoteStep) => {
21	  const basePremium = basePremiumOf(step.items);
22	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
23	  return { premium: basePremium + firstInsuranceSurcharge + PROCESSING_FEE };
24	};
25	
26	export const runScenario = (scenario: Scenario): unknown => {
27	  return { results: scenario.steps.map(quoteForStep) };
28	};
29

