17	    const result = runScenario({
18	      customer: { yearsWithMHPCO: 0 },
19	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
20	    });
21	    expect(result).toEqual({ results: [{ premium: 115 }] });
